def normalize_email(raw: str) -> str:
    """Pre: raw es str. Post: lower strip con @. Raises ValueError si falta @."""
    s = raw.strip().lower()
    if "@" not in s:
        raise ValueError("falta @ en el email")
    return s
print(normalize_email("  A@B.COM "))
try:
    normalize_email("x")
except ValueError as e:
    print("err", e)

