from typing import Optional, Tuple

def parse_monto(raw: str) -> Tuple[bool, Optional[int], Optional[str]]:
    try:
        n = int(raw.strip())
    except ValueError:
        return False, None, "no es entero"
    if n < 0:
        return False, None, "fuera de rango de dominio"
    return True, n, None
for v in ["0", "10", "-1", "x"]:
    print(v, parse_monto(v))

